CASE WHEN w.site_id = #{params.personalSiteId} THEN 'default' ELSE 'own' END as relation_source, CASE WHEN excl.id IS NOT NULL THEN 1 ELSE 0 END as is_excluded,
(SELECT COUNT(*) FROM gb_site_workflow_relation swr WHERE swr.workflow_id = w.id AND swr.relation_type = 'include') as related_sites_count FROM gb_workflow w LEFT JOIN gb_categories c ON w.category_id = c.id LEFT JOIN gb_sites s ON w.site_id = s.id
