ORDER BY w.create_time DESC

SELECT w.*, c.name as category_name, c.icon as category_icon, s.name as site_name, -- 统一的可见性状态： -- 1. 自有工作流（site_id = 当前网站）：使用工作流本身的enabled -- 2. 用户默认站点（site_id = personalSiteId）： -- - 如果有关联记录（rel.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站工作流：使用关联表的is_visible CASE WHEN w.site_id = #{siteId} THEN w.enabled WHEN w.site_id = #{params.personalSiteId} THEN (CASE WHEN rel.id IS NOT NULL THEN rel.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE rel.is_visible END as is_visible, -- 关联来源标识 CASE WHEN w.site_id = #{siteId} THEN 'own' WHEN w.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN w.site_id = #{params.personalSiteId} AND rel.id IS NULL AND excl.id IS NOT NULL THEN 1 ELSE 0 END as is_excluded FROM gb_workflow w LEFT JOIN gb_categories c ON w.category_id = c.id LEFT JOIN gb_sites s ON w.site_id = s.id LEFT JOIN gb_site_workflow_relation excl ON w.id = excl.workflow_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude' LEFT JOIN gb_site_workflow_relation rel ON w.id = rel.workflow_id AND rel.site_id = #{siteId} AND rel.relation_type = 'include' WHERE ( w.site_id = #{siteId}
OR w.site_id = #{params.personalSiteId}
OR rel.id IS NOT NULL )
AND w.workflow_code like concat('%', #{workflowCode}, '%')
AND w.workflow_name like concat('%', #{workflowName}, '%')
AND w.trigger_type = #{triggerType}
AND w.category_id = #{categoryId}
AND w.enabled = #{enabled}
ORDER BY relation_source DESC, w.create_time DESC

